const input = $input.first();
const payload = input.json.body ?? input.json ?? {};

const leadTemperature = String(payload.lead_temperature ?? '').toLowerCase().trim();
const fullName = payload.full_name ?? payload.name ?? 'Lead sin nombre';
const intent = payload.intent ?? 'unknown';
const nextAction = payload.next_action ?? 'manual_review_required';
const sourceChannel = payload.source_channel ?? payload.source_platform ?? 'unknown';
const originAsset = payload.origin_asset ?? payload.source_detail ?? 'unknown';
const territory = payload.territory ?? 'SW Mallorca';
const nexusLeadId = payload.nexus_lead_id ?? payload.lead_id ?? '';
const receivedAt = payload.received_at ?? new Date().toISOString();
const notes = payload.notes ?? '';
const email = payload.email ?? '';
const phone = payload.phone ?? payload.whatsapp ?? '';

if (!['hot', 'warm', 'manual_review'].includes(leadTemperature)) {
  return [];
}

let alertLabel = 'OPERATIVA';
let sla = '48h';
if (leadTemperature === 'hot') {
  alertLabel = 'PRIORITARIA';
  sla = '24h';
}
if (leadTemperature === 'manual_review') {
  alertLabel = 'REVISION';
  sla = 'Revisar cuanto antes';
}

const subject = `[Anclora] Lead ${leadTemperature.toUpperCase()} - ${fullName}`;
const text = [
  `Nuevo lead ${leadTemperature} en Nexus`,
  '',
  `Nombre: ${fullName}`,
  `Intent: ${intent}`,
  `Canal: ${sourceChannel}`,
  `Asset: ${originAsset}`,
  `Zona: ${territory}`,
  `Siguiente accion: ${nextAction}`,
  `SLA sugerido: ${sla}`,
  `Lead ID: ${nexusLeadId || 'pendiente'}`,
  `Email: ${email || 'n/d'}`,
  `Telefono: ${phone || 'n/d'}`,
  notes ? `Notas: ${notes}` : null,
  `Recibido: ${receivedAt}`
].filter(Boolean).join('\n');

const html = `
  <div style="font-family:Arial,sans-serif;line-height:1.5;color:#111827;max-width:720px;margin:0 auto;padding:24px;">
    <div style="border-radius:16px;padding:20px 24px;background:#0f172a;color:#f8fafc;">
      <div style="font-size:12px;letter-spacing:.18em;text-transform:uppercase;opacity:.72;">Alerta ${alertLabel}</div>
      <h1 style="margin:8px 0 0;font-size:28px;line-height:1.15;">Nuevo lead ${leadTemperature}</h1>
      <p style="margin:12px 0 0;font-size:15px;opacity:.88;">${fullName} requiere atencion comercial.</p>
    </div>
    <div style="margin-top:18px;border:1px solid #e5e7eb;border-radius:16px;padding:20px 24px;background:#ffffff;">
      <p><strong>Intent:</strong> ${intent}</p>
      <p><strong>Canal:</strong> ${sourceChannel}</p>
      <p><strong>Asset:</strong> ${originAsset}</p>
      <p><strong>Zona:</strong> ${territory}</p>
      <p><strong>Siguiente accion:</strong> ${nextAction}</p>
      <p><strong>SLA sugerido:</strong> ${sla}</p>
      <p><strong>Lead ID:</strong> ${nexusLeadId || 'pendiente'}</p>
      <p><strong>Email:</strong> ${email || 'n/d'}</p>
      <p><strong>Telefono:</strong> ${phone || 'n/d'}</p>
      ${notes ? `<p><strong>Notas:</strong> ${notes}</p>` : ''}
      <p><strong>Recibido:</strong> ${receivedAt}</p>
    </div>
  </div>
`;

return [{
  json: {
    should_send_alert: true,
    lead_temperature: leadTemperature,
    alert_label: alertLabel,
    sla,
    subject,
    text,
    html,
    full_name: fullName,
    nexus_lead_id: nexusLeadId,
    next_action: nextAction,
    source_channel: sourceChannel,
    origin_asset: originAsset,
    territory: territory,
    received_at: receivedAt
  }
}];
